 input  mcif2cdp_wr_rsp_complete;

 input [31:0] pwrbus_ram_pd;

 wire [78:0] cdp_dp2wdma_pd;
 wire        cdp_dp2wdma_ready;
 wire        cdp_dp2wdma_valid;
 wire [86:0] cdp_rdma2dp_pd;
